class Solution:
    def findNthDigit(self, n):
        d = 1
        count = 9
        start = 1
        while n > d * count:
            n -= d * count
            d += 1
            count *= 10
            start *= 10
        number = start + (n - 1) // d
        digit_index = (n - 1) % d
        return int(str(number)[digit_index])

