var findNthDigit = function(n) {
    let d = 1;
    let count = 9;
    let start = 1;
    while (n > d * count) {
        n -= d * count;
        d += 1;
        count *= 10;
        start *= 10;
    }
    const number = start + Math.floor((n - 1) / d);
    const digitIndex = (n - 1) % d;
    return Number(String(number)[digitIndex]);
};
